// // This module implements a 16-bit comparator circuit that outputs three signals: lt for 'greater than', gt for 'less than', and eq for 'not equal'.
module top_module(lt, gt, eq, data1, data2);input [15:0] data1, data2;
   output lt, gt, eq;

   assign lt = data1 < data2;
   assign gt = data1 > data2;
   assign eq = data1 == data2;endmodule
